import Animated, { useAnimatedStyle, useSharedValue, withTiming } from 'react-native-reanimated';
import { Pressable } from 'react-native';

export function NativeMotionToggle() {
  const progress = useSharedValue(0);
  const style = useAnimatedStyle(() => ({ opacity: 0.5 + progress.value * 0.5, transform: [{ scale: 0.96 + progress.value * 0.04 }] }));
  return <Pressable onPress={() => { progress.value = withTiming(progress.value ? 0 : 1, { duration: 180 }); }}><Animated.View style={style} /></Pressable>;
}

